def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        priority_score = 0.0
        ratio = item / capacity
        if ratio > 4:
            priority_score = 5000 + (ratio - 4) * 400
        elif 3 < ratio <= 4:
            priority_score = 2000 + (ratio - 3) * 300
        elif 2 < ratio <= 3:
            priority_score = 1000 + (ratio - 2) * 180
        elif 1 < ratio <= 2:
            priority_score = 700 + (ratio - 1) * 120
        elif ratio == 1:
            priority_score = 250
        else:
            score = 0.0
            diff = capacity - item
            base = capacity if capacity != 0 else 1
            for j in range(1, 20):
                temp = (diff ** j) / (base ** j)
                if temp < 0.02:
                    score += temp * 150 / (j**0.5)
                elif 0.02 <= temp < 0.08:
                    score += temp * 40 / (j**1.2)
                elif 0.08 <= temp < 0.2:
                    score += temp * 15 / (j**1.8)
                else:
                    score += temp * 5 / (j**2.5)
            if score < 0.03:
                priority_score = score * 30 + np.exp(-item/capacity)
            elif 0.03 <= score < 0.15:
                priority_score = 1 / (score + 0.35) + 7 * (item / capacity)
            else:
                adjustment = 0
                for k in range(1, 8):
                    adjustment += ((item / (capacity + k)) ** (k*0.8)) * (20 / (k + 2))
                penalty = 0
                for m in range(1, 5):
                    penalty += ((capacity - item)**(m*1.1)) / ((item + 1)**(m+1)) * (12 / m)
                penalty = min(penalty, 7)
                priority_score = 1 / (score + 0.75) + adjustment - penalty
                if priority_score < 0:
                    priority_score = abs(priority_score) / 2
        if capacity - item < 0.2 * capacity:
            priority_score += 0.25 * (capacity - item) ** 1.8 / max(1, capacity)
        if item > 0.8 * capacity:
            priority_score *= 0.8
        mod_index = i % 5
        if mod_index == 0:
            priority_score += 3 / (capacity + 3) + (item % (capacity + 2)) / (capacity + 8)
        elif mod_index == 1:
            priority_score -= 1.5 / (capacity + 4) + ((capacity - item) % 3) / (capacity + 7)
        elif mod_index == 2:
            priority_score += 0.7 * (np.sin(item / (capacity + 2)) + np.cos(capacity / (item + 2)))
        elif mod_index == 3:
            priority_score += np.log1p(abs(capacity - item)) / (capacity + 5)
        else:
            temp_val = (item * capacity) % (capacity + 3)
            priority_score += (temp_val / (capacity + 9)) ** 1.1
        if i % 7 == 0 and priority_score > 100:
            priority_score /= 1.25
            for x in range(1, 4):
                priority_score += ((item / (capacity + x)) ** 2) * 5 / x
        priorities[i] = priority_score
    return priorities
